def _dbt_model_column_to_nested(
    dbt_model_column: DbtModelColumn,
) -> DbtModelColumnNested:
    """Convert flat DbtModelColumn to nested format."""
    attrs = DbtModelColumnAttributes()
    _populate_dbt_model_column_attrs(attrs, dbt_model_column)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        dbt_model_column,
        _DBT_MODEL_COLUMN_REL_FIELDS,
        DbtModelColumnRelationshipAttributes,
    )
    return DbtModelColumnNested(
        guid=dbt_model_column.guid,
        type_name=dbt_model_column.type_name,
        status=dbt_model_column.status,
        version=dbt_model_column.version,
        create_time=dbt_model_column.create_time,
        update_time=dbt_model_column.update_time,
        created_by=dbt_model_column.created_by,
        updated_by=dbt_model_column.updated_by,
        classifications=dbt_model_column.classifications,
        classification_names=dbt_model_column.classification_names,
        meanings=dbt_model_column.meanings,
        labels=dbt_model_column.labels,
        business_attributes=dbt_model_column.business_attributes,
        custom_attributes=dbt_model_column.custom_attributes,
        pending_tasks=dbt_model_column.pending_tasks,
        proxy=dbt_model_column.proxy,
        is_incomplete=dbt_model_column.is_incomplete,
        provenance_type=dbt_model_column.provenance_type,
        home_id=dbt_model_column.home_id,
        depth=dbt_model_column.depth,
        immediate_upstream=dbt_model_column.immediate_upstream,
        immediate_downstream=dbt_model_column.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _dbt_model_column_from_nested(nested: DbtModelColumnNested) -> DbtModelColumn:
    """Convert nested format to flat DbtModelColumn."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else DbtModelColumnAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DBT_MODEL_COLUMN_REL_FIELDS,
        DbtModelColumnRelationshipAttributes,
    )
    return DbtModelColumn(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_dbt_model_column_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _dbt_model_column_to_nested_bytes(
    dbt_model_column: DbtModelColumn, serde: Serde
) -> bytes:
    """Convert flat DbtModelColumn to nested JSON bytes."""
    return serde.encode(_dbt_model_column_to_nested(dbt_model_column))


def _dbt_model_column_from_nested_bytes(data: bytes, serde: Serde) -> DbtModelColumn:
    """Convert nested JSON bytes to flat DbtModelColumn."""
    nested = serde.decode(data, DbtModelColumnNested)
    return _dbt_model_column_from_nested(nested)


